using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change 1: HasIndex() now throws for Cosmos — removed.

        // Breaking change 2: Discriminator property renamed from "Discriminator" to "$type".
        // Existing documents use "Discriminator", so we pin the old name to stay compatible.
        modelBuilder.Entity<Blog>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Blog>("Blog");

        // Breaking change 3: Id values no longer include the discriminator prefix.
        // Existing documents have ids like "Blog|1", so we keep that format.
        modelBuilder.Entity<Blog>()
            .Property(b => b.Id)
            .HasValueGenerator<DiscriminatorPrefixIdGenerator>();
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

/// <summary>
/// Restores the EF Core 8 id format: "{Discriminator}|{Guid}".
/// </summary>
class DiscriminatorPrefixIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    protected override string NextValue(EntityEntry entry)
        => entry.Metadata.GetDiscriminatorValue() + "|" + Guid.NewGuid().ToString();
}

